previewCss:
.darma-loader-darma-custom-304 {
  width: fit-content;
  font-size: 34px;
  font-family: monospace;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #2563eb);
  --g:linear-gradient(90deg,var(--loader-color, #2563eb),var(--loader-secondary-color, #38bdf8)) no-repeat text;
  background:var(--g) 0,var(--g) 1ch,var(--g) 2ch,var(--g) 3ch,var(--g) 4ch,var(--g) 5ch,var(--g) 6ch;
  animation: 
    darma-loader-darma-custom-304-l17-0 1s linear infinite alternate,
    darma-loader-darma-custom-304-l17-1 2s linear infinite;
}
.darma-loader-darma-custom-304:before {
  content: "Loading";
}
@keyframes darma-loader-darma-custom-304-l17-0 {
  0%   {background-size: 1ch 0   }
  100% {background-size: 1ch 100%}
}
@keyframes darma-loader-darma-custom-304-l17-1 {
  0%,50%    {background-position-y: 100%, 0}
  50.01%,to {background-position-y: 0, 100%}
}

